SELECT /* base.ec.pd :: PdCategoryProd :: selectList */ * , ste.site_nm AS site_nm , cat.category_nm AS category_nm , prd.prod_nm AS prod_nm FROM pd_category_prod p LEFT JOIN sy_site ste ON ste.site_id = site_id LEFT JOIN pd_category cat ON cat.category_id = category_id LEFT JOIN pd_prod prd ON prd.prod_id = prod_id
ORDER BY category_prod_id ASC ORDER BY category_prod_id DESC ORDER BY reg_date ASC ORDER BY reg_date DESC ORDER BY reg_date DESC
LIMIT #{limit} OFFSET #{offset}

